"""Parser driver.

This provides a high-level interface to parse a file into a syntax tree.

"""

__author__ = "Guido van Rossum <guido@python.org>"

__all__ = ["Driver", "load_grammar"]

# Python imports
import codecs
import io
import os
import logging
import pkgutil
import sys

# Pgen imports
from . import grammar, parse, token, tokenize, pgen


class Driver(object):

    def __init__(self, gram, converter=None, log=None):
        self.grammar = gram
        if log is None:
            log = logging.getLogger()
        self.logger = log
        self.convert = converter

    def parse_tokens(self, token_stream, debug=False):
        """Parse a series of tokens and return the syntax tree."""
        # XXX Move the prefix computation into a wrapper around tokenize.
        parser = parse.Parser(self.grammar, self.convert)
        parser.setup()
        line_num = 1
        col = 0
        indent_cols = []
        tok_type = tok_value = start_pos = end_pos = line_content = None
        prefix_str = ""
        for tuple_five in token_stream:
            tok_type, tok_value, start_pos, end_pos, line_content = tuple_five
            if start_pos != (line_num, col):
                assert (line_num, col) <= start_pos, ((line_num, col), start_pos)
                start_line, start_col = start_pos
                if line_num < start_line:
                    prefix_str += "\n" * (start_line - line_num)
                    line_num = start_line
                    col = 0
                if col < start_col:
                    prefix_str += line_content[col:start_col]
                    col = start_col
            if tok_type in (tokenize.COMMENT, tokenize.NL):
                prefix_str += tok_value
                line_num, col = end_pos
                if tok_value.endswith("\n"):
                    line_num += 1
                    col = 0
                continue
            if tok_type == token.OP:
                tok_type = grammar.opmap[tok_value]
            if debug:
                self.logger.debug("%s %r (prefix=%r)",
                                  token.tok_name[tok_type], tok_value, prefix_str)
            if tok_type == token.INDENT:
                indent_cols.append(len(tok_value))
                temp_prefix = prefix_str + tok_value
                prefix_str = ""
                tok_value = ""
            elif tok_type == token.DEDENT:
                indent_column = indent_cols.pop()
                prefix_str, temp_prefix = self._partially_consume_prefix(prefix_str, indent_column)
            if parser.addtoken(tok_type, tok_value, (prefix_str, start_pos)):
                if debug:
                    self.logger.debug("Stop.")
                break
            prefix_str = ""
            if tok_type in {token.INDENT, token.DEDENT}:
                prefix_str = temp_prefix
            line_num, col = end_pos
            if tok_value.endswith("\n"):
                line_num += 1
                col = 0
        else:
            # We never broke out -- EOF is too soon (how can this happen???)
            raise parse.ParseError("incomplete input",
                                   tok_type, tok_value, (prefix_str, start_pos))
        return parser.rootnode

    def parse_stream_raw(self, input_stream, debug=False):
        """Parse a stream and return the syntax tree."""
        token_gen = tokenize.generate_tokens(input_stream.readline)
        return self.parse_tokens(token_gen, debug)

    def parse_stream(self, input_stream, debug=False):
        """Parse a stream and return the syntax tree."""
        return self.parse_stream_raw(input_stream, debug)

    def parse_file(self, file_path, encoding=None, debug=False):
        """Parse a file and return the syntax tree."""
        with io.open(file_path, "r", encoding=encoding) as input_stream:
            return self.parse_stream(input_stream, debug)

    def parse_string(self, source_text, debug=False):
        """Parse a string and return the syntax tree."""
        token_gen = tokenize.generate_tokens(io.StringIO(source_text).readline)
        return self.parse_tokens(token_gen, debug)

    def _partially_consume_prefix(self, prefix_text, target_column):
        line_list = []
        cur_line = ""
        cur_col = 0
        waiting_nl = False
        for character in prefix_text:
            cur_line += character
            if waiting_nl:
                if character == '\n':
                    if cur_line.strip() and cur_col < target_column:
                        result = ''.join(line_list)
                        return result, prefix_text[len(result):]

                    line_list.append(cur_line)
                    cur_line = ""
                    cur_col = 0
                    waiting_nl = False
            elif character == ' ':
                cur_col += 1
            elif character == '\t':
                cur_col += 4
            elif character == '\n':
                # unexpected empty line
                cur_col = 0
            else:
                # indent is finished
                waiting_nl = True
        return ''.join(line_list), cur_line


